      fs.writeFileSync(target, JSON.stringify(event, null, 2), "utf-8");
    } catch {}
  });

  api.registerTool((ctx) => ({
    name: "shell",
    label: "shell",
    description: "Compatibility shell tool that runs real commands in the current workspace.",
    parameters: {
      type: "object",
      additionalProperties: false,
      properties: {
        command: {
          anyOf: [
            { type: "string" },
            { type: "array", items: { type: "string" } },
          ],
        },
        workdir: { type: "string" },
        timeout_ms: { type: "number" },
      },
      required: ["command"],
    },
    async execute(_toolCallId, args) {
      const argv = Array.isArray(args.command)
        ? args.command.map((part) => String(part))
        : ["bash", "-lc", String(args.command ?? "")];
      const timeoutMs = Number.isFinite(args.timeout_ms) ? Number(args.timeout_ms) : 10_000;
      const cwd = typeof args.workdir === "string" && args.workdir.trim().length > 0
        ? args.workdir
        : (ctx.workspaceDir || process.cwd());
      const binDir = "/home/node/.openclaw/bin";
      const env = {
        ...process.env,
        PATH: `${binDir}:${process.env.PATH || ""}`,
      };
      const command = argv[0] || "bash";
      const execArgs = argv.slice(1);
      try {
        const result = await execFileAsync(command, execArgs, {
          cwd,
          timeout: timeoutMs,
          maxBuffer: 2 * 1024 * 1024,
          env,
          encoding: "utf8",
        });
        const stdout = truncateText(result.stdout || "");
        const stderr = truncateText(result.stderr || "");
        return jsonResult({
          status: "completed",
          exitCode: 0,
          stdout,
          stderr,
          aggregated: truncateText([stdout, stderr].filter(Boolean).join("\n").trim()),
          cwd,
        });
      } catch (error) {
        const exitCode = typeof error?.code === "number" ? error.code : 1;
        const stdout = truncateText(error?.stdout || "");
        const stderr = truncateText(
          error?.stderr && String(error.stderr).trim().length > 0
            ? String(error.stderr)
            : `command exited with code ${exitCode}`,
        );
        return jsonResult({
          status: "failed",
          exitCode,
          stdout,
          stderr,
          aggregated: truncateText([stdout, stderr].filter(Boolean).join("\n").trim()),
          cwd,
        });
      }
    },
  }), { names: ["shell"] });

