      const plan = Array.isArray(args.plan) ? args.plan.map((item) => ({
        step: String(item.step ?? "").trim(),
        status: String(item.status ?? "").trim(),
      })) : [];
      const root = ctx.workspaceDir || process.cwd();
      const stateDir = path.join(root, ".openclaw");
      fs.mkdirSync(stateDir, { recursive: true });
      const sessionKey = ctx.sessionKey || "main";
      const target = path.join(stateDir, `plan-${sessionKey.replace(/[^a-zA-Z0-9._-]+/g, "_")}.json`);
      const payload = { sessionKey, updatedAt: Date.now(), plan };
      fs.writeFileSync(target, JSON.stringify(payload, null, 2), "utf-8");
      return jsonResult({ ok: true, sessionKey, path: target, plan });
    },
  }), { names: ["update_plan"] });
