/**
 * Imported Workflow - Read-Only Handler
 * 
 * This handler runs when /new command is issued.
 * It operates with read-only permissions for safety.
 */

const handler = async (event) => {
  // Only trigger on 'new' command
  if (event.type !== "command" || event.action !== "new") {
    return;
  }

  console.log(`[imported-workflow] Workflow triggered`);
  console.log(`  Session: ${event.sessionKey}`);
  console.log(`  Timestamp: ${event.timestamp.toISOString()}`);
  console.log(`  Permissions: read-only`);

  // Read-only operations only - no modifications
  // This workflow is for auditing/monitoring purposes

  // Optional: Send confirmation to user
  event.messages.push("📄 Imported workflow executed (read-only mode)");
};

export default handler;
